/**
 * @param {number[]} nums
 * @param {number} k
 * @return {number}
 */
function solve(nums, k) {
    const N = nums.length;
    if (k === 0) {
        return 0;
    }

    // Maximum possible peaks in a circular array is floor(N/2)
    if (k > Math.floor(N / 2)) {
        return -1;
    }

    const INF = 1e18;

    // Step 1: Precalculate Cost[i]
    // Cost[i] is the minimum cost to make nums[i] a peak, assuming its neighbors are unchanged.
    const Cost = new Array(N);
    for (let i = 0; i < N; i++) {
        const left = nums[(i - 1 + N) % N];
        const right = nums[(i + 1) % N];
        // Required value: max(left, right) + 1
        const required = Math.max(left, right) + 1;
        Cost[i] = Math.max(0, required - nums[i]);
    }

    /**
     * Solves the minimum cost independent set of size K on a path.
     * @param {number} start_idx - Starting index of the path segment.
     * @param {number} end_idx - Ending index of the path segment.
     * @param {number} K_target - Target number of peaks in this segment.
     * @param {number} initial_cost - Cost already incurred before the start_idx.
     * @returns {number} Minimum total cost, or INF if impossible.
     */
    const solve_linear = (start_idx, end_idx, K_target, initial_cost) => {
        if (K_target < 0) return INF;
        if (start_idx > end_idx) {
            return K_target === 0 ? initial_cost : INF;
        }

        const len = end_idx - start_idx + 1;

        // DP[j][s]: min cost to select j peaks up to current index, 
        // where s=0 means current index is NOT selected, s=1 means it IS selected.
        // We use two arrays, prev and curr, to simulate the loop.

        // Initialize DP for the first element in the segment (start_idx)
        let P = Array(K_target + 1).fill(0).map(() => [INF, INF]);

        // Base case for start_idx
        // 0 peaks, not selected: cost 0 relative to segment start
        P[0][0] = 0; 
        // 1 peak, selected: cost Cost[start_idx]
        P[1][1] = Cost[start_idx];

        // Iterate through the rest of the segment
        for (let i = start_idx + 1; i <= end_idx; i++) {
            let C = Array(K_target + 1).fill(0).map(() => [INF, INF]);

            for (let j = 0; j <= K_target; j++) {
                // Case 1: Current index i is NOT selected (s=0)
                // We can come from i-1 being selected or not selected.
                C[j][0] = Math.min(P[j][0], P[j][1]);

                // Case 2: Current index i IS selected (s=1)
                // We MUST come from i-1 being NOT selected (P[j-1][0]).
                if (j > 0) {
                    if (P[j - 1][0] !== INF) {
                        C[j][1] = P[j - 1][0] + Cost[i];
                    }
                }
            }
            P = C;
        }

        const min_cost = Math.min(P[K_target][0], P[K_target][1]);
        return min_cost === INF ? INF : min_cost + initial_cost;
    };


    // --- Case 1: Index 0 is NOT selected (s_0 = 0) ---
    // Solve linear DP on indices [1, N-1] for K peaks. Initial cost 0.
    let result1 = solve_linear(1, N - 1, k, 0);

    // --- Case 2: Index 0 IS selected (s_0 = 1) ---
    // Requires K >= 1. We need K-1 more peaks in the remaining path [2, N-1].
    // Index 1 must be NP (since 0 is P).
    let result2 = INF;
    if (k >= 1) {
        // Solve linear DP on indices [2, N-1] for K-1 peaks. Initial cost Cost[0].
        result2 = solve_linear(2, N - 1, k - 1, Cost[0]);
    }

    const final_min_cost = Math.min(result1, result2);

    return final_min_cost === INF ? -1 : final_min_cost;
}

